# 全局变量
employees = []

# 输入获取
while True:
    try:
        employees.append(list(map(int, input().split())))
    except:
        break


# 算法入口
def getResult(employees):
    employees.sort(key=lambda x: (-x[0], -x[1]))

    for i in range(10):
        print(" ".join(map(str, employees[i])))


# 算法调用
getResult(employees)
